#!/usr/bin/env python3
# -*- coding: utf-8 -*-

import os
import subprocess
import json
import pytest
import common


def is_location_dataview_uniq(locations):
    for location in locations:
        if location["caret"]["file"].endswith("dataview-uniq.c"):
            return True
    return False


def is_warning_allowed(message):
    # File 'dataview-uniq.c' is generated by asn1scc and it contain a warning (normal gcc output)
    # dataview-uniq.c:24:27: warning: comparison is always true due to limited range of data type [-Wtype-limits]
    #  24 |     ret = ((-2147483648LL <= (*(pVal))) && ((*(pVal)) <= 2147483647LL));
    # since this file is not a part of runtime nor drivers, this warning is allowed here
    return (message["kind"] == "warning" and
            message["message"] == "comparison is always true due to limited range of data type" and
            is_location_dataview_uniq(message["locations"]))


def warning_description(message):
    return json.dumps(message, sort_keys=True, indent=4)


def parse_export(line):
    line = line.strip().removeprefix("export ")
    separator = line.find("=")
    if separator > 0:
        key=line[:separator]
        value=line[separator+1:]
        return (key, value)
    return None


def find_custom_environment(project_root):
    makefile_path = os.path.abspath(os.path.join(project_root, "Makefile"))
    current_path_value = os.path.abspath(project_root) + "/"
    result = {}
    with open(makefile_path, "r") as makefile:
        exports = filter(lambda line: line.startswith("export "), makefile.readlines())
        for export in exports:
            var = parse_export(export)
            if var:
               result[var[0]] = var[1].replace("$(CURRENT_DIR)", current_path_value)
    return result


def prepare_custom_environment(project_root):
    env = os.environ.copy()
    custom_env = find_custom_environment(project_root)
    env = env | custom_env
    # compile files with additional flag to output json
    if "PARTITION_1_USER_CFLAGS" in env:
        env["PARTITION_1_USER_CFLAGS"] = env["PARTITION_1_USER_CFLAGS"] + " -fdiagnostics-format=json"
    else:
        env["PARTITION_1_USER_CFLAGS"] = "-fdiagnostics-format=json"
    return env


def check_project_has_no_build_warnings(project_root):
    # do standard clean and build
    common.do_clean_build(project_root)

    build = common.do_build(project_root, ["samrh71", "debug"])
    stderr = build.stderr.decode("utf-8")
    assert build.returncode == 0, f"Compilation errors: \n{stderr}"

    partition_root = os.path.abspath(os.path.join(project_root, "work/build/node_1"))
    try:
        # clean only generated object files using generated Makefile
        process = subprocess.run(["make", "-f", "Makefile.node_1", "clean"], cwd=partition_root, shell=False, capture_output=True)
    except (OSError, ValueError, subprocess.SubprocessError):
        pytest.fail(f"Unable to clean binaries {process.stderr}")

    try:
        env = prepare_custom_environment(project_root)
        process = subprocess.run(["make", "-f", "Makefile.node_1", "debug"], cwd=partition_root, shell=False, capture_output=True, env=env)
        # check if all generated messages are allowed
        lines = list(filter(lambda line: line, process.stderr.decode('utf-8').splitlines()))
        for line in lines:
            messages = json.loads(line)
            for message in messages:
                assert is_warning_allowed(message), f"Unexpected warning in project {project_root}:\n{warning_description(message)}"
    except (OSError, ValueError, subprocess.SubprocessError):
        pytest.fail(f"Unable to build binaries {process.stderr}")


def test_samrh71_rtems_build():
    check_project_has_no_build_warnings("samrh71-rtems-cpu-usage/TEST-SAMRH71-CPU-USAGE")
    check_project_has_no_build_warnings("samrh71-rtems-cpu-config-off/samrh71-rtems-rt-rtos-no-init")
    check_project_has_no_build_warnings("samrh71-rtems-cpu-config-on/samrh71-rtems-cpu-config-default")
    check_project_has_no_build_warnings("samrh71-rtems-cpu-config-on/samrh71-rtems-cpu-config-freq")


if __name__ == "__main__":
    test_samrh71_rtems_build()
